// Created: 2026-04-30

/**
 * CLAUDE.md Byte Budget — PostToolUse/Write hook
 *
 * `tests/perf/test-token-overhead.sh` enforces `CLAUDE.md ≤ 4800 bytes`
 * (~1200 tokens) as a hard CI failure. CLAUDE.md is loaded into every
 * session's context, so bloat costs every user every turn.
 *
 * This hook fires immediately after a Write/Edit on CLAUDE.md and warns
 * if the file crossed the budget. Catches at edit-time so the user can
 * trim before commit, instead of finding out at CI.
 *
 * Advisory only — does NOT block. Opt out with
 * `ORK_DISABLE_CLAUDE_MD_BUDGET=1`.
 */

import { existsSync, statSync } from 'node:fs';
import { basename, isAbsolute, resolve } from 'node:path';
import type { HookInput, HookResult, HookContext } from '../../types.js';
import { outputSilentSuccess, getField } from '../../lib/common.js';
import { NOOP_CTX } from '../../lib/context.js';

const HOOK_NAME = 'posttool/write/claude-md-byte-budget';

// Hard limit enforced by tests/perf/test-token-overhead.sh
const BYTE_LIMIT = 4800;
// Soft warning at 90% of the limit so the user knows they're approaching
const SOFT_LIMIT = Math.floor(BYTE_LIMIT * 0.9); // 4320

function isClaudeMd(path: string): boolean {
  return basename(path) === 'CLAUDE.md';
}

function getFileSize(projectDir: string, path: string): number | null {
  const abs = isAbsolute(path) ? path : resolve(projectDir, path);
  if (!existsSync(abs)) return null;
  try {
    return statSync(abs).size;
  } catch {
    return null;
  }
}

export function claudeMdByteBudget(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  if (process.env.ORK_DISABLE_CLAUDE_MD_BUDGET === '1') return outputSilentSuccess();
  if (input.tool_name !== 'Write' && input.tool_name !== 'Edit') return outputSilentSuccess();

  const filePath = getField<string>(input, 'tool_input.file_path') || '';
  if (!isClaudeMd(filePath)) return outputSilentSuccess();

  const size = getFileSize(ctx.projectDir, filePath);
  if (size === null) {
    ctx.log(HOOK_NAME, `CLAUDE.md not readable at ${filePath} — silent`);
    return outputSilentSuccess();
  }

  if (size <= SOFT_LIMIT) {
    ctx.log(HOOK_NAME, `CLAUDE.md ${size}B / ${BYTE_LIMIT}B — within budget`);
    return outputSilentSuccess();
  }

  const overage = size - BYTE_LIMIT;
  const isHard = size > BYTE_LIMIT;

  const advice = isHard
    ? `CI test-token-overhead.sh will FAIL (${size}B > ${BYTE_LIMIT}B limit, +${overage}B over). ` +
      `Extract the most recent additions to \`docs/<topic>.md\` and leave a 1-line pointer ` +
      `in CLAUDE.md.`
    : `Approaching CI budget: ${size}B / ${BYTE_LIMIT}B (${Math.round((size / BYTE_LIMIT) * 100)}% used). ` +
      `Future additions risk pushing over.`;

  ctx.log(HOOK_NAME, `${isHard ? 'OVER' : 'NEAR'} budget: ${size}B / ${BYTE_LIMIT}B`);

  return {
    continue: true,
    hookSpecificOutput: {
      hookEventName: 'PostToolUse',
      additionalContext: `[claude-md-byte-budget] ${advice} (Opt out with ORK_DISABLE_CLAUDE_MD_BUDGET=1.)`,
    },
  };
}

// Testing exports
export { BYTE_LIMIT, SOFT_LIMIT, isClaudeMd, getFileSize };
